import json

# Re-process chapters 35 and 36 with correct edges
chapters_data = {
    "a-dance-with-dragons-chapter-35": [
        {"pair_a": "arron", "pair_b": "emrick", "direction": "symmetric", "edge_type": "TRAVELS_WITH", "snippet": "Arron and Emrick from Fair Isle", "para": 1},
        {"pair_a": "leathers", "pair_b": "jax", "direction": "symmetric", "edge_type": "TRAVELS_WITH", "snippet": "Leathers and Jax are the only two to accept so far", "para": 2},
    ],
    "a-dance-with-dragons-chapter-36": [],
}

for chapter_name, emit_list in chapters_data.items():
    if chapter_name == "a-dance-with-dragons-chapter-36":
        input_path = "/Users/mnoth/source/asoiaf-chat/working/wiki/pass2-buckets/meta-chapters-adwd/comention-candidates/a-dance-with-dragons-chapter-36.candidates.jsonl"
    else:
        input_path = f"/Users/mnoth/source/asoiaf-chat/working/wiki/pass2-buckets/meta-chapters-adwd/comention-candidates/{chapter_name}.candidates.jsonl"

    output_path = input_path.replace("/comention-candidates/", "/prose-edges-haiku/").replace(".candidates.jsonl", ".comention-edges.jsonl")

    candidates = []
    with open(input_path, 'r') as f:
        for line in f:
            if line.strip():
                candidates.append(json.loads(line))

    decisions = []
    emit_set = {(e["pair_a"], e["pair_b"]) for e in emit_list}
    emit_dict = {(e["pair_a"], e["pair_b"]): e for e in emit_list}

    for cand in candidates:
        pair = (cand.get("pair_a"), cand.get("pair_b"))

        if pair in emit_set:
            e = emit_dict[pair]
            decision = {
                "decision": "emit_edge",
                "candidate_kind": "comention",
                "evidence_kind": "wiki-chapter-summary",
                "source_slug": cand["pair_a"],
                "target_slug": cand["pair_b"],
                "direction": e["direction"],
                "edge_type": e["edge_type"],
                "evidence_chapter": cand["evidence_chapter"],
                "evidence_snippet": e["snippet"],
                "evidence_section": "## Narrative Arc",
                "evidence_paragraph_index": e["para"],
                "confidence_tier": 1
            }
        else:
            decision = {
                "decision": "reject_just_mention",
                "candidate_kind": "comention",
                "pair_a": cand["pair_a"],
                "pair_b": cand["pair_b"],
                "evidence_chapter": cand["evidence_chapter"],
                "reason": "temporal-cooccurrence-not-relational"
            }

        decisions.append(decision)

    with open(output_path, 'w') as f:
        for d in decisions:
            f.write(json.dumps(d) + '\n')

    emit_count = len([d for d in decisions if d["decision"] == "emit_edge"])
    reject_count = len([d for d in decisions if d["decision"] == "reject_just_mention"])
    print(f"[updated] {chapter_name}.candidates.jsonl → {emit_count} emit_edge, {reject_count} reject_just_mention")

EOF
